          "items": {
            "type": "object"
          }
        }
      },
      "additionalProperties": false,
      "required": [
        "expectation_id",
        "status"
      ]
    },
    "GapItem": {
      "type": "object",
      "properties": {
        "kind": {
          "type": "string",
          "minLength": 1
        },
        "error_type": {
          "type": "string",
          "minLength": 1
        },
        "expected": {},
        "actual": {},
        "evidence_ref": {
          "type": "string",
          "minLength": 1
        },
        "raw": {},
        "incomplete": {
          "type": "boolean"
        }
      },
      "additionalProperties": false
    }
  },
  "required": [
    "business_expectations",
    "overall_fulfillment",
    "reasoning_summary"
  ]
}
```

### 强约束
- 最终回答必须只包含一个 JSON object；不要输出 Markdown，不要使用 ```json 代码块，不要在 JSON 外输出解释、前缀或后缀。
- 最终回答首字符必须是 `{`，末字符必须是 `}`。
- JSON 字符串内部如需引用用户原词，禁止直接写未转义英文双引号；请使用中文引号“”或转义为 `\"`。
- 必须包含 `required` 列表中的所有字段。
- 每个字段值必须匹配 schema 中的类型。
- 以下字段必须非空（空字符串/空数组/空对象/None 均视为不合规，会被阻断）：['business_expectations', 'overall_fulfillment', 'reasoning_summary']
- `additionalProperties: false`：禁止输出 schema 未定义的字段。
- 禁止把 schema 里的类型描述符（如 "string"）原样当作内容填进去——每个字段必须填入真实内容。

messages.reasoning_content:
我们被要求评估一个营销计划意图识别系统的输出。用户输入是“帮我看看上季度买了重疾险的客户都是啥样的？”，预期意图是“customer_portrait”，期望置信度0.95，目标值“重疾险”。实际输出中，系统识别为“other”意图，置信度0.5，无目标值。显然，系统未能识别出正确的意图。

我们需要根据提供的评判标准和维度来评估。

首先，我们需要定义business_expectations。根据critical_intent_dimensions：intent_label, required_slots_or_entities, confidence_threshold, fallback_policy, dispatch_boundary。此外，我们还需要考虑用户的实际业务意图：用户想要分析购买重疾险的客户画像，这应该被归类为customer_portrait意图，并提取出保险类型“重疾险”作为目标值。

因此，我们可以定义以下期望：

1. 意图标签应为“customer_portrait”（或相应的中文意图，但系统输出中使用了intent_name“其他意图”，而预期是customer_portrait）。
2. 置信度应达到或超过0.95（根据reference_contract的confidence）。
3. 必须提取出目标值“重疾险”（target_value）。
4. 系统不应回退到fallback意图（即不应是“其他意图”）。
5. 意图调度边界：该查询应该被路由到customer_portrait处理模块，而不是通用或other意图。

业务期望应该拆分得更具体。每个期望应该是一个可独立验证的维度。我们可以创建如下的expectation_id：

- 意图标签识别为“客户画像”意图
- 置信度达到阈值
- 目标实体“重疾险”被提取
- 避免误识别为其他意图

但考虑到系统输出中已经表明是other意图，所以大部分期望会是not_fulfilled。

在fulfillment_assessments中，我们对每个期望进行评估。输出中需要包含overall_fulfillment，状态应为not_fulfilled，因为核心意图识别错误。

注意，我们不应归因于内部代码或配置，只基于实际输出和预期之间的差距。

根据schema，我们需要提供：

- business_expectations: 期望列表
- fulfillment_assessments: 评估列表
- overall_fulfillment: 整体满足情况
- expected: 可能是一般性的预期对象，但schema里没有指定类型，似乎是any。可能我们可以放空对象或包含预期值。schema中"expected": {}，似乎是自由对象。类似地，"missing", "wrong", "extra" 是GapItem数组，我们可以根据差距提供。
- evidence: 数组
- reasoning_summary: 总结

我们还需要遵守JSON格式规范：必须是有效的JSON，没有代码块。

让我们更仔细地看schema中的字段。

```json
{
  "type": "object",
  "properties": {
    "business_expectations": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/BusinessExpectation"
      },
      "minItems": 1
    },
    "fulfillment_assessments": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/FulfillmentAssessment"
      }
    },
    "overall_fulfillment": {
      "type": "object",
      "minProperties": 1
    },
    "expected": {},
    "missing": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/GapItem"
      }
    },
    "wrong": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/GapItem"
      }
    },
    "extra": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/GapItem"
      }
    },
    "evidence": {
      "type": "array",
      "items": {}
    },
    "reasoning_summary": {
      "type": "string",
      "minLength": 1
    }
  },
  ...
}
```

注意：fulfillment_assessments不是required，但为了完整性，应该提供。overall_fulfillment是object，minProperties 1，所以我们需要一个具有至少一个属性的对象。我们可以包含status和score等。类似地，expected可以是空对象或包含预期内容的对象。但是schema没有定义overall_fulfillment的内部结构，我们可以自行定义。同理，expected、missing、wrong等字段不是必须的，但我们可以提供。根据前面的说明，必需字段是business_expectations, overall_fulfillment, reasoning_summary。所以我们可以只提供这三个，但最好也提供fulfillment_assessments和evidence等，以便于解释。

但为了保险，我们可以提供所有字段，但必须确保每个字段的类型正确。

现在构建business_expectations。

BusinessExpectation的定义：

```json
{
  "type": "object",
  "properties": {
    "expectation_id": {
      "type": "string",
      "minLength": 1
    },
    "downstream_consumer": {
      "type": "string",
      "minLength": 1
    },
    "user_intent": {
      "type": "string",
      "minLength": 1
    },
    "expected_outcome": {
      "type": "string",
      "minLength": 1
    },
    "required_capabilities": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      }
    },
    "acceptance_criteria": {
      "type": "array",
      "items": {}
    },
    "boundary": {
      "type": "object"
    },
    "priority": {
      "type": "string",
      "minLength": 1
    },
    "evidence_refs": {
      "type": "array",
      "items": {
        "type": "object"
      }
    }
  },
  "additionalProperties": false,
  "required": [
    "expectation_id"
  ]
}
```

所以对于每个期望，我们至少需要expectation_id。但其他字段如果能提供可以更详细。不过，要求“expectation_id 必须是描述性的中文短语，禁止使用 E1/E2/exp_01 等占位符 ID”。所以我们可以使用类似“意图标签识别为customer_portrait”这样的ID。但为了更符合中文，可以使用“意图识别为客群画像”或类似的。但预期意图是customer_portrait，我们可以直接用英文或中文。因为用户提示中可能用到了英文intent名称。我们可以使用“意图识别为customer_portrait”。

我们构建几个期望：

1. expectation_id: "意图标签识别为customer_portrait"
   downstream_consumer: "下游营销规划模块"
   user_intent: "用户希望分析上季度购买重疾险的客户画像"
   expected_outcome: "系统输出意图为customer_portrait"
   required_capabilities: ["意图识别", "实体提取"]
   acceptance_criteria: ["意图标签等于customer_portrait"]
   boundary: {}
   priority: "high"
   evidence_refs: []

2. expectation_id: "置信度达到0.95阈值"
   ...
3. expectation_id: "目标实体提取为重疾险"
   ...
4. expectation_id: "未回退到其他意图"
   ...

评估每个期望时，我们需要FulfillmentAssessment：

```json
{
  "type": "object",
  "properties": {
    "expectation_id": {
      "type": "string",
      "minLength": 1
    },
    "status": {
      "type": "string",
      "minLength": 1
    },
    "score": {
      "type": [
        "number",
        "null"
      ]
    },
    "expected_evidence": {
      "type": "array",
      "items": {}
    },
    "actual_evidence": {
      "type": "array",
      "items": {}
    },
    "downstream_impact": {
      "type": "string",
      "minLength": 1
    },
    "blocking": {
      "type": "boolean"
    },
    "confidence": {
      "type": [
        "number",
        "null"
      ]
    },
    "evidence_refs": {
      "type": "array",
      "items": {
        "type": "object"
      }
    }
  },
  "additionalProperties": false,
  "required": [
    "expectation_id",
    "status"
  ]
}
```

我们需要为每个期望提供评估，状态为fulfilled或not_fulfilled。由于实际输出意图为other，显然意图标签不正确，所以评估为not_fulfilled。同样，其他期望也会是not_fulfilled。

overall_fulfillment: 我们可以设置为包含status: "not_fulfilled"和score: 0的对象。

reasoning_summary: 用中文描述为什么没有满足。

现在我们需要提供evidence参照。run_trace中有execution_trace和extracted_output。我们可以使用它们作为证据。

在expected字段，我们可以放置参考预期值。在missing字段列出缺失的内容，wrong字段列出错误的内容，extra字段列出多余的内容。

例如：

missing: 预期意图customer_portrait缺失，实际为other。
wrong: 意图标签错误为other，置信度仅为0.5。
extra: 可能有多余的“其他意图”输出。

但GapItem的定义：

```json
{
  "type": "object",
  "properties": {
    "kind": {
      "type": "string",
      "minLength": 1
    },
    "error_type": {
      "type": "string",
      "minLength": 1
    },
    "expected": {},
    "actual": {},
    "evidence_ref": {
      "type": "string",
      "minLength": 1
    },
    "raw": {},
    "incomplete": {
      "type": "boolean"
    }
  },
  "additionalProperties": false
}
```

我们可以根据情况填写。

evidence数组：我们可以放置一些证据描述。

现在，构建整个JSON。

注意，所有的字符串都必须有内容，不能是空字符串。required_capabilities等数组如果不是必须，可以省略，但为了保证JSON有效，我们可以按需提供。由于BusinessExpectation的required只有expectation_id，我们可以只提供这个，但为了丰富，可以多提供一些。

但要注意，如果提供了某个字段，必须符合其类型要求。例如，acceptance_criteria是数组，boundary是对象，不能是字符串。如果不想提供，可以省略该字段，因为只有expectation_id是必需的。但为了更完整，我会提供较全面的信息。

另外，strict要求：禁止输出schema未定义的字段。所以我们必须确保每个字段都在定义中，不能添加额外属性。

就FulfillmentAssessment而言，只有expectation_id和status是必须的。其他可选。

Overall_fulfillment没有定义内部属性，但我们可以添加status和score，因为它是object，minProperties 1，我们可以自由定义属性。

让我们开始构建。

首先，business_expectations数组，包含四个期望。

1. 意图标签识别为customer_portrait
2. 目标实体提取为重疾险
3. 置信度不低于0.95
4. 避免回退为其他意图

但可能第四个和前两个有重叠，但可以独立。

expectation_id:
"意图标签识别为customer_portrait"
"目标实体提取为重疾险"
"置信度达到0.95或以上"
"避免回退为other意图"

对于每个，评估status为not_fulfilled，因为实际输出是other意图，没有target_value，置信度0.5。

在fulfillment_assessments中，针对每个期望，给出状态。

注意，FulfillmentAssessment中的expected_evidence和actual_evidence可以为空数组。

downstream_impact: 描述对下游的影响。

blocking: 可以设置为true，表示该失败会阻塞下游。

confidence: 可以给0或null。

evidence_refs: 可引用trace中的某个部分。

现在构建missing和wrong数组。

missing: 预期意图customer_portrait，目标值重疾险，置信度0.95，但在实际输出中都缺失。我们可以创建几个gap item。

wrong: 实际意图为other，置信度为0.5。

extra: 可能额外输出了subIntent“其他意图”，但这不是预期的。

现在，证据部分：从extracted_output中可以看出。

我们使用中文撰写所有字段。

现在，让我们写出完整的JSON。

注意：reasoning_summary必须是字符串，汇总整个评估。

一些细节：

- 在business_expectations中，acceptance_criteria可以是包含字符串的数组。
- required_capabilities可以是["意图识别", "实体提取"]。
- boundary可以是{}。
- priority可以是"高"或"high"。

确保所有字符串都有minLength 1，所以不能为空。

另外，overall_fulfillment中我们可以包含"status": "not_fulfilled", "score": 0。

expected字段：我们可以放参考预期对象，比如{"intent": "customer_portrait", "confidence": 0.95, "target_value": "重疾险"}，但这不是必须的，可以放空{}，但为了更有用，可以放期望的对象。但是expected是any类型，可以自由。

我们按照直觉来做。

让我们生成JSON。

注意：JSON中不能有注释。

开始编写。
